INSERT INTO public.services (slug, title, short_description, path, seo_title, seo_description, published, sort_order, content)
VALUES
(
  $v$ui-ux-design$v$,
  $v$UI/UX-дизайн для B2B$v$,
  $v$Проектируем интерфейсы для сайтов, кабинетов и сервисов, где важны понятный сценарий, доверие, заявки и аккуратная передача в разработку.$v$,
  $v$/services/ui-ux-design$v$,
  $v$UI/UX-дизайн для B2B-сайтов и веб-сервисов | Skybric$v$,
  $v$Проектируем UX/UI для B2B-сайтов, веб-сервисов и личных кабинетов: сценарии, структура, прототипы, UI-система, адаптив и handoff для разработки.$v$,
  true,
  0,
  $v${"heroTitle":"UI/UX-дизайн, который объясняет продукт и ведёт клиента к следующему шагу","heroSubtitle":"Разбираем аудиторию, роли, сценарии, форму заявки и ограничения бизнеса. На выходе — структура, прототипы, визуальная система и макеты, которые можно передавать в разработку.","ctaPrimary":"Обсудить дизайн-задачу","valuePoints":["B2B-сценарии","прототипы и UI-система","handoff для разработки"],"cardPains":["пользователь не понимает, что делать дальше","форма заявки собирает мало контекста","разработка получает красивые экраны без логики"],"cardResult":"Понятная интерфейсная система: сценарии, экраны, состояния, адаптив и комментарии для разработки.","pains":[{"problem":"Интерфейс выглядит нормально, но сценарий не ведёт к действию","manifestation":"Кнопки, блоки и формы есть, но пользователь не понимает, какой шаг выбрать и чем отличается предложение.","consequence":"Часть трафика не доходит до заявки, а менеджеры получают мало полезного контекста."},{"problem":"Структура страниц собрана вокруг компании, а не вокруг клиента","manifestation":"На первом экране много общих фраз, услуги похожи друг на друга, а доказательства и следующий шаг спрятаны ниже.","consequence":"B2B-покупатель дольше оценивает fit и чаще уходит без контакта."},{"problem":"Макеты сложно реализовать без потери логики","manifestation":"Нет состояний форм, ошибок, пустых экранов, адаптива и правил для повторяемых компонентов.","consequence":"Разработка тратит время на догадки, а итоговый интерфейс расходится с исходной идеей."}],"solutions":["UX-аудит текущего интерфейса","карта пользовательских сценариев","информационная архитектура","wireframes и прототипы","UI-концепция и дизайн-система","адаптивные макеты","состояния форм, ошибок и пустых экранов","handoff для frontend-команды"],"useCases":["B2B-сайты","личные кабинеты","SaaS-интерфейсы","CRM и внутренние панели","fintech-сервисы","формы заявок и onboarding"],"finalCta":{"title":"Нужен интерфейс, который не просто выглядит хорошо, а объясняет задачу?","text":"Опишите текущий продукт, аудиторию и слабое место. Посмотрим, где дизайн должен упростить путь пользователя."},"visual":{"eyebrow":"design system","title":"сценарий → прототип → UI → handoff","nodes":["Аудит","Сценарии","Прототип","UI","Handoff"],"metrics":["логика","адаптив","состояния"]},"ctaSecondary":"Посмотреть состав работ","processSteps":["Разбираем продукт, аудиторию, текущие экраны и бизнес-ограничения","Собираем карту пользовательских сценариев и структуру интерфейса","Проектируем UX-прототипы, состояния, формы и точки принятия решения","Создаём UI-систему: сетка, компоненты, адаптив, визуальная иерархия","Передаём макеты, спецификацию и сопровождаем разработку до запуска"],"businessResults":["помогает быстрее объяснить ценность продукта или услуги","снижает трение в формах, заявках и ключевых сценариях","делает интерфейс понятнее для клиентов, менеджеров и руководителей","создаёт основу для разработки без случайных экранов и ручных правок","помогает аккуратно развивать продукт после запуска"],"deliverables":["UX-аудит текущего интерфейса или сайта","карта сценариев и пользовательских путей","информационная архитектура","wireframes и кликабельные прототипы","UI-концепция и дизайн-система","адаптивные макеты","состояния форм, ошибок и пустых экранов","handoff для разработки","проверка реализации после сборки"],"whyCustom":["дизайн строится вокруг конкретной сделки, роли пользователя и бизнес-процесса","можно учесть текущую CRM, документы, статусы, роли и ограничения команды","интерфейс не заставляет бизнес подстраиваться под чужой шаблон","макеты передаются так, чтобы разработка понимала логику, а не только внешний вид","после запуска дизайн-систему можно развивать без пересборки всего продукта"],"faq":[{"question":"Можно ли начать только с дизайн-аудита?","answer":"Да. Если уже есть сайт или продукт, сначала фиксируем слабые места в структуре, UX, контенте и форме заявки, а затем определяем объём редизайна."},{"question":"Делаете ли вы только дизайн без разработки?","answer":"Да, если нужна проектная работа по UX/UI и handoff. Но при необходимости можем подключить frontend и backend, чтобы не терять логику при реализации."},{"question":"Что нужно от клиента на старте?","answer":"Текущий сайт или продукт, описание аудитории, цели страницы или интерфейса, примеры заявок, ограничения по бренду и доступ к аналитике, если она уже есть."},{"question":"Будут ли макеты готовы для разработки?","answer":"Да. Передаём структуру, адаптивные экраны, состояния компонентов, тексты для ключевых зон и комментарии по логике."},{"question":"Можно ли редизайнить без остановки текущего сайта?","answer":"Да. Обычно новая структура и дизайн собираются отдельно, а перенос на продакшен планируется после согласования и проверки."},{"question":"Вы обещаете рост конверсии после редизайна?","answer":"Нет. Мы не обещаем неподтверждённые цифры. Задача дизайна — убрать трение, сделать предложение понятнее и подготовить основу для измерения результата."}]}$v$::jsonb
),
(
  $v$website-redesign$v$,
  $v$Редизайн B2B-сайта$v$,
  $v$Пересобираем сайт вокруг оффера, структуры, доверия и заявки: без визуального мусора, общих фраз и случайных блоков.$v$,
  $v$/services/website-redesign$v$,
  $v$Редизайн B2B-сайта — структура, UX, тексты и UI | Skybric$v$,
  $v$Редизайн B2B-сайтов: аудит текущей структуры, новый сценарий страниц, UX/UI, тексты, формы, адаптив и подготовка к разработке.$v$,
  true,
  1,
  $v${"heroTitle":"Редизайн B2B-сайта, который делает предложение понятнее","heroSubtitle":"Смотрим, где сайт не объясняет продукт, теряет доверие или усложняет заявку. Затем пересобираем структуру, тексты, интерфейс и форму контакта.","ctaPrimary":"Обсудить редизайн сайта","valuePoints":["аудит текущего сайта","новая структура","форма и CTA"],"cardPains":["сайт выглядит устаревшим или разрозненным","услуги не собраны в понятные money-pages","заявка не передаёт нужный контекст"],"cardResult":"Обновлённая структура и визуальная система сайта с понятными страницами услуг, CTA и формой заявки.","pains":[{"problem":"Сайт не продаёт конкретную услугу","manifestation":"На страницах много общих описаний, а оффер, fit, результат и следующий шаг не собраны в одну логику.","consequence":"Тёплый посетитель не понимает, почему стоит оставить заявку именно сейчас."},{"problem":"Доверие не поддержано интерфейсом","manifestation":"Слабая иерархия, разные стили блоков, нет аккуратного объяснения процесса и состава работ.","consequence":"Сайт выглядит дешевле самой услуги и хуже проходит первичный vendor-check."},{"problem":"SEO-структура не помогает продажам","manifestation":"Коммерческие направления не вынесены в отдельные страницы, а внутренние ссылки не ведут пользователя к заявке.","consequence":"Сложнее собирать спрос по конкретным услугам и прогревать посетителя внутри сайта."}],"solutions":["UX-аудит текущего сайта","новая карта страниц и money-pages","структура hero, услуг, FAQ и CTA","копирайтинг ключевых блоков","визуальная система и UI-компоненты","адаптив desktop / tablet / mobile","форма заявки и состояния отправки","передача в разработку или реализация на Next.js"],"useCases":["корпоративные сайты","сайты услуг","B2B-лендинги","сайты перед запуском рекламы","сайты после смены позиционирования","многостраничные service hubs"],"finalCta":{"title":"Текущий сайт не объясняет услугу так, как её продаёт команда?","text":"Пришлите ссылку и коротко опишите, что должно измениться. Начнём с разборa структуры и точек потери заявки."},"visual":{"eyebrow":"redesign flow","title":"аудит → структура → тексты → UI → запуск","nodes":["Текущий сайт","Слабые места","Money-pages","UI","Форма"],"metrics":["оффер","доверие","заявка"]},"ctaSecondary":"Посмотреть состав работ","processSteps":["Разбираем продукт, аудиторию, текущие экраны и бизнес-ограничения","Собираем карту пользовательских сценариев и структуру интерфейса","Проектируем UX-прототипы, состояния, формы и точки принятия решения","Создаём UI-систему: сетка, компоненты, адаптив, визуальная иерархия","Передаём макеты, спецификацию и сопровождаем разработку до запуска"],"businessResults":["помогает быстрее объяснить ценность продукта или услуги","снижает трение в формах, заявках и ключевых сценариях","делает интерфейс понятнее для клиентов, менеджеров и руководителей","создаёт основу для разработки без случайных экранов и ручных правок","помогает аккуратно развивать продукт после запуска"],"deliverables":["UX-аудит текущего интерфейса или сайта","карта сценариев и пользовательских путей","информационная архитектура","wireframes и кликабельные прототипы","UI-концепция и дизайн-система","адаптивные макеты","состояния форм, ошибок и пустых экранов","handoff для разработки","проверка реализации после сборки"],"whyCustom":["дизайн строится вокруг конкретной сделки, роли пользователя и бизнес-процесса","можно учесть текущую CRM, документы, статусы, роли и ограничения команды","интерфейс не заставляет бизнес подстраиваться под чужой шаблон","макеты передаются так, чтобы разработка понимала логику, а не только внешний вид","после запуска дизайн-систему можно развивать без пересборки всего продукта"],"faq":[{"question":"Можно ли начать только с дизайн-аудита?","answer":"Да. Если уже есть сайт или продукт, сначала фиксируем слабые места в структуре, UX, контенте и форме заявки, а затем определяем объём редизайна."},{"question":"Делаете ли вы только дизайн без разработки?","answer":"Да, если нужна проектная работа по UX/UI и handoff. Но при необходимости можем подключить frontend и backend, чтобы не терять логику при реализации."},{"question":"Что нужно от клиента на старте?","answer":"Текущий сайт или продукт, описание аудитории, цели страницы или интерфейса, примеры заявок, ограничения по бренду и доступ к аналитике, если она уже есть."},{"question":"Будут ли макеты готовы для разработки?","answer":"Да. Передаём структуру, адаптивные экраны, состояния компонентов, тексты для ключевых зон и комментарии по логике."},{"question":"Можно ли редизайнить без остановки текущего сайта?","answer":"Да. Обычно новая структура и дизайн собираются отдельно, а перенос на продакшен планируется после согласования и проверки."},{"question":"Вы обещаете рост конверсии после редизайна?","answer":"Нет. Мы не обещаем неподтверждённые цифры. Задача дизайна — убрать трение, сделать предложение понятнее и подготовить основу для измерения результата."}]}$v$::jsonb
),
(
  $v$websites$v$,
  $v$Сайты для бизнеса$v$,
  $v$Разрабатываем корпоративные сайты и посадочные страницы, которые быстро объясняют продукт, снимают лишние вопросы и доводят пользователя до следующего шага без визуального шума и путаницы.$v$,
  $v$/services/websites$v$,
  $v$Сайты для бизнеса — разработка корпоративных сайтов и лендингов | Skybric$v$,
  $v$Проектируем и разрабатываем сайты для B2B-компаний: структура, UX, тексты, SEO-база, формы, аналитика и интеграция заявок с CRM.$v$,
  true,
  2,
  $v${"heroTitle":"Сайт, который объясняет продукт и ведёт клиента к заявке","heroSubtitle":"Собираем структуру, тексты, интерфейс, SEO-основу и формы так, чтобы посетитель быстро понял предложение, увидел следующий шаг и не потерялся между разделами.","ctaPrimary":"Обсудить сайт","ctaSecondary":"Посмотреть, что входит в работу","valuePoints":["структура под B2B-продажи","формы и аналитика","SEO-база для money-pages"],"cardPains":["сайт выглядит нормально, но не объясняет продукт","заявки идут в разные каналы и теряются","страницы не поддерживают SEO-рост"],"cardResult":"Понятный сайт с сильной структурой, формами, аналитикой и маршрутом заявки в нужную систему.","pains":[{"problem":"Посетитель не понимает, что делать дальше","manifestation":"На странице много общих формулировок, услуги похожи друг на друга, CTA не связан с задачей клиента.","consequence":"Пользователь уходит до заявки или пишет с неполным контекстом."},{"problem":"Заявки не доходят до команды","manifestation":"Формы, Telegram и почта живут отдельно, ответственный не всегда видит новый лид вовремя.","consequence":"Часть обращений теряет скорость, а руководитель не видит реальную картину входящего потока."},{"problem":"Сайт не готов к SEO","manifestation":"Нет понятной структуры money-pages, слабые title/description, мало внутренней связности.","consequence":"Органический спрос сложнее собирать, даже если продукт уже понятен рынку."},{"problem":"Сложно обновлять контент","manifestation":"Каждая правка превращается в ручную задачу для разработчика или ломает визуальную систему.","consequence":"Маркетинг медленнее тестирует офферы, страницы и новые услуги."}],"solutions":["структура сайта и карта страниц","UX-прототипы ключевых экранов","тексты для hero, услуг, CTA и FAQ","адаптивная frontend-разработка","формы заявок и события аналитики","интеграция с CRM, Telegram или почтой","SEO-метаданные и базовая техническая оптимизация"],"processSteps":["Разбираем процесс и ограничения","Проектируем архитектуру и сценарии","Собираем интерфейс, backend и контент","Интегрируем с CRM, Telegram, аналитикой или API","Тестируем, запускаем MVP и дорабатываем по данным"],"businessResults":["помогает быстрее объяснить сложный продукт","снижает риск потери заявки после формы","делает путь пользователя до контакта короче","создаёт основу для SEO и рекламных посадочных страниц","упрощает дальнейшие изменения контента"],"useCases":["B2B-компании","fintech и финансовые сервисы","консалтинг и профессиональные услуги","SaaS и веб-сервисы","компании с длинным циклом сделки","проекты перед запуском рекламы"],"deliverables":["анализ задачи и ограничений","архитектура решения","UX / UI","frontend","backend","интеграции","тестирование","запуск","документация по логике","доработки после запуска"],"whyCustom":["решение встраивается в текущие процессы, а не заставляет менять весь порядок работы","можно учесть роли, статусы, документы, источники заявок и внутренние правила","данные и логика остаются под контролем бизнеса","архитектуру можно развивать после MVP без пересборки с нуля","команда получает инструмент под рабочий сценарий, а не ещё один разрозненный сервис"],"faq":[{"question":"Сколько стоит работа?","answer":"Стоимость зависит от объёма логики, интеграций и готовности материалов. После короткого разбора называем понятный диапазон и MVP-объём."},{"question":"Можно ли начать с MVP?","answer":"Да. Обычно безопаснее начать с одного процесса, проверить сценарий на реальных данных и затем расширять систему."},{"question":"Сколько занимает запуск?","answer":"Срок зависит от объёма и интеграций. Небольшой MVP можно планировать отдельно от полноценной версии, чтобы быстрее проверить гипотезу."},{"question":"Какие интеграции возможны?","answer":"Сайт, Telegram, CRM, формы, email, телефония, 1С, базы знаний и внутренние API, если у системы есть доступный способ обмена данными."},{"question":"Что нужно от клиента?","answer":"Контекст задачи, примеры заявок или документов, доступы к тестовым средам и человек, который знает рабочий процесс изнутри."},{"question":"Можно ли дорабатывать после запуска?","answer":"Да. После запуска появляются реальные сценарии, по которым уточняются правила, интерфейсы, интеграции и тексты."},{"question":"Как защищаются данные?","answer":"Мы ограничиваем доступы, не просим лишние права, разделяем тестовую и рабочую среду и заранее согласуем, какие данные передаются во внешние сервисы."}],"finalCta":{"title":"Нужен сайт, который продаёт не обещаниями, а понятной структурой?","text":"Опишите продукт, аудиторию и текущий сайт. Подскажем, какую структуру стоит собрать первой."},"visual":{"eyebrow":"website system","title":"страница → форма → CRM → менеджер","nodes":["Hero","Услуги","Форма","CRM","Follow-up"],"metrics":["структура","заявка","SEO"]}}$v$::jsonb
),
(
  $v$saas-product-design$v$,
  $v$Product design для SaaS$v$,
